// RetryPipelineTests.cs
// TDD tests for the error-retry pipeline.
// We follow red/green/refactor: each test is written to fail first,
// then we add just enough production code to make it green.

using Moq;
using Pipeline.Core;
using Xunit;

public class RetryPipelineTests
{
    // ---------------------------------------------------------------------------
    // Test 1 (RED): Empty queue produces a zero-count summary
    // ---------------------------------------------------------------------------
    [Fact]
    public void EmptyQueue_RunsPipeline_ReturnsZeroCounts()
    {
        var mockQueue = new Mock<IQueue<string>>();
        // TryDequeue always returns false (empty queue)
        mockQueue.Setup(q => q.TryDequeue(out It.Ref<string?>.IsAny)).Returns(false);

        var mockProcessor = new Mock<IItemProcessor<string>>();
        var options = new RetryOptions { MaxRetries = 3, BaseDelayMs = 0 };
        var pipeline = new RetryPipeline<string>(mockQueue.Object, mockProcessor.Object, options);

        var result = pipeline.Run();

        Assert.Equal(0, result.TotalProcessed);
        Assert.Equal(0, result.TotalFailed);
        Assert.Equal(0, result.DeadLetterCount);
    }

    // ---------------------------------------------------------------------------
    // Test 2 (RED): All items succeed on first attempt
    // ---------------------------------------------------------------------------
    [Fact]
    public void AllItemsSucceed_ReportsCorrectCounts()
    {
        var items = new Queue<string>(["item-1", "item-2", "item-3"]);
        var mockQueue = new Mock<IQueue<string>>();
        mockQueue.Setup(q => q.TryDequeue(out It.Ref<string?>.IsAny))
            .Returns((out string? val) =>
            {
                if (items.TryDequeue(out var item))
                {
                    val = item;
                    return true;
                }
                val = null;
                return false;
            });

        var mockProcessor = new Mock<IItemProcessor<string>>();
        // Always succeed
        mockProcessor.Setup(p => p.Process(It.IsAny<string>())).Returns(ProcessResult.Success);

        var options = new RetryOptions { MaxRetries = 3, BaseDelayMs = 0 };
        var pipeline = new RetryPipeline<string>(mockQueue.Object, mockProcessor.Object, options);

        var result = pipeline.Run();

        Assert.Equal(3, result.TotalProcessed);
        Assert.Equal(0, result.TotalFailed);
        Assert.Equal(0, result.DeadLetterCount);
    }

    // ---------------------------------------------------------------------------
    // Test 3 (RED): Item that always fails is sent to dead-letter queue
    // ---------------------------------------------------------------------------
    [Fact]
    public void AlwaysFailingItem_ExceedsMaxRetries_GoesToDeadLetterQueue()
    {
        var items = new Queue<string>(["bad-item"]);
        var mockQueue = new Mock<IQueue<string>>();
        mockQueue.Setup(q => q.TryDequeue(out It.Ref<string?>.IsAny))
            .Returns((out string? val) =>
            {
                if (items.TryDequeue(out var item)) { val = item; return true; }
                val = null; return false;
            });

        var mockProcessor = new Mock<IItemProcessor<string>>();
        // Always fail
        mockProcessor.Setup(p => p.Process(It.IsAny<string>())).Returns(ProcessResult.Failure);

        var mockDlq = new Mock<IQueue<string>>();

        var options = new RetryOptions { MaxRetries = 3, BaseDelayMs = 0 };
        var pipeline = new RetryPipeline<string>(mockQueue.Object, mockProcessor.Object, options, mockDlq.Object);

        var result = pipeline.Run();

        Assert.Equal(0, result.TotalProcessed);
        Assert.Equal(1, result.TotalFailed);
        Assert.Equal(1, result.DeadLetterCount);
        // Verify the item was enqueued to the dead-letter queue
        mockDlq.Verify(q => q.Enqueue("bad-item"), Times.Once);
    }

    // ---------------------------------------------------------------------------
    // Test 4 (RED): Item succeeds after N retries (transient failure)
    // ---------------------------------------------------------------------------
    [Fact]
    public void TransientFailure_SucceedsOnRetry_NotSentToDlq()
    {
        var items = new Queue<string>(["flaky-item"]);
        var mockQueue = new Mock<IQueue<string>>();
        mockQueue.Setup(q => q.TryDequeue(out It.Ref<string?>.IsAny))
            .Returns((out string? val) =>
            {
                if (items.TryDequeue(out var item)) { val = item; return true; }
                val = null; return false;
            });

        var callCount = 0;
        var mockProcessor = new Mock<IItemProcessor<string>>();
        // Fail twice then succeed
        mockProcessor.Setup(p => p.Process(It.IsAny<string>()))
            .Returns(() => ++callCount < 3 ? ProcessResult.Failure : ProcessResult.Success);

        var options = new RetryOptions { MaxRetries = 3, BaseDelayMs = 0 };
        var pipeline = new RetryPipeline<string>(mockQueue.Object, mockProcessor.Object, options);

        var result = pipeline.Run();

        Assert.Equal(1, result.TotalProcessed);
        Assert.Equal(0, result.TotalFailed);
        Assert.Equal(0, result.DeadLetterCount);
        Assert.Equal(2, result.TotalRetries); // 2 retries before success
    }

    // ---------------------------------------------------------------------------
    // Test 5 (RED): Retry count is bounded by MaxRetries
    // ---------------------------------------------------------------------------
    [Fact]
    public void ProcessorCalled_ExactlyMaxRetriesPlusOne_Times()
    {
        var items = new Queue<string>(["bad-item"]);
        var mockQueue = new Mock<IQueue<string>>();
        mockQueue.Setup(q => q.TryDequeue(out It.Ref<string?>.IsAny))
            .Returns((out string? val) =>
            {
                if (items.TryDequeue(out var item)) { val = item; return true; }
                val = null; return false;
            });

        var mockProcessor = new Mock<IItemProcessor<string>>();
        mockProcessor.Setup(p => p.Process(It.IsAny<string>())).Returns(ProcessResult.Failure);

        var options = new RetryOptions { MaxRetries = 4, BaseDelayMs = 0 };
        var pipeline = new RetryPipeline<string>(mockQueue.Object, mockProcessor.Object, options);

        pipeline.Run();

        // 1 initial attempt + 4 retries = 5 calls total
        mockProcessor.Verify(p => p.Process("bad-item"), Times.Exactly(5));
    }

    // ---------------------------------------------------------------------------
    // Test 6 (RED): Progress reporter receives events during processing
    // ---------------------------------------------------------------------------
    [Fact]
    public void ProgressReporter_ReceivesEvents_DuringProcessing()
    {
        var items = new Queue<string>(["item-1", "item-2"]);
        var mockQueue = new Mock<IQueue<string>>();
        mockQueue.Setup(q => q.TryDequeue(out It.Ref<string?>.IsAny))
            .Returns((out string? val) =>
            {
                if (items.TryDequeue(out var item)) { val = item; return true; }
                val = null; return false;
            });

        var mockProcessor = new Mock<IItemProcessor<string>>();
        mockProcessor.Setup(p => p.Process(It.IsAny<string>())).Returns(ProcessResult.Success);

        var mockReporter = new Mock<IProgressReporter>();

        var options = new RetryOptions { MaxRetries = 3, BaseDelayMs = 0 };
        var pipeline = new RetryPipeline<string>(
            mockQueue.Object, mockProcessor.Object, options,
            progressReporter: mockReporter.Object);

        pipeline.Run();

        // Should have reported progress for each processed item
        mockReporter.Verify(r => r.Report(It.Is<ProgressReport>(p => p.Status == ItemStatus.Processed)), Times.Exactly(2));
    }

    // ---------------------------------------------------------------------------
    // Test 7 (RED): Progress reporter is notified on retry attempts
    // ---------------------------------------------------------------------------
    [Fact]
    public void ProgressReporter_ReceivesRetryEvent_WhenItemFails()
    {
        var items = new Queue<string>(["flaky-item"]);
        var mockQueue = new Mock<IQueue<string>>();
        mockQueue.Setup(q => q.TryDequeue(out It.Ref<string?>.IsAny))
            .Returns((out string? val) =>
            {
                if (items.TryDequeue(out var item)) { val = item; return true; }
                val = null; return false;
            });

        var callCount = 0;
        var mockProcessor = new Mock<IItemProcessor<string>>();
        // Fail once, then succeed
        mockProcessor.Setup(p => p.Process(It.IsAny<string>()))
            .Returns(() => ++callCount < 2 ? ProcessResult.Failure : ProcessResult.Success);

        var mockReporter = new Mock<IProgressReporter>();

        var options = new RetryOptions { MaxRetries = 3, BaseDelayMs = 0 };
        var pipeline = new RetryPipeline<string>(
            mockQueue.Object, mockProcessor.Object, options,
            progressReporter: mockReporter.Object);

        pipeline.Run();

        mockReporter.Verify(r => r.Report(It.Is<ProgressReport>(p => p.Status == ItemStatus.Retrying)), Times.Once);
        mockReporter.Verify(r => r.Report(It.Is<ProgressReport>(p => p.Status == ItemStatus.Processed)), Times.Once);
    }

    // ---------------------------------------------------------------------------
    // Test 8 (RED): Mixed items produce correct summary
    // ---------------------------------------------------------------------------
    [Fact]
    public void MixedItems_ProduceCorrectFinalSummary()
    {
        // 3 items: 2 succeed, 1 always fails
        var items = new Queue<string>(["ok-1", "bad-item", "ok-2"]);
        var mockQueue = new Mock<IQueue<string>>();
        mockQueue.Setup(q => q.TryDequeue(out It.Ref<string?>.IsAny))
            .Returns((out string? val) =>
            {
                if (items.TryDequeue(out var item)) { val = item; return true; }
                val = null; return false;
            });

        var mockProcessor = new Mock<IItemProcessor<string>>();
        mockProcessor.Setup(p => p.Process("ok-1")).Returns(ProcessResult.Success);
        mockProcessor.Setup(p => p.Process("ok-2")).Returns(ProcessResult.Success);
        mockProcessor.Setup(p => p.Process("bad-item")).Returns(ProcessResult.Failure);

        var options = new RetryOptions { MaxRetries = 2, BaseDelayMs = 0 };
        var pipeline = new RetryPipeline<string>(mockQueue.Object, mockProcessor.Object, options);

        var result = pipeline.Run();

        Assert.Equal(2, result.TotalProcessed);
        Assert.Equal(1, result.TotalFailed);
        Assert.Equal(1, result.DeadLetterCount);
        Assert.Equal(2, result.TotalRetries); // bad-item retried MaxRetries times
    }
}

