        var mockProcessor = new Mock<IItemProcessor<string>>();
        var options = new RetryOptions { MaxRetries = 3, BaseDelayMs = 0 };
        var pipeline = new RetryPipeline<string>(mockQueue.Object, mockProcessor.Object, options);

        var result = pipeline.Run();

